INSERT INTO dict_professional_summaries (template_name, rank_tier, target_industry, target_role, template_text, example_output) VALUES ('warrant_officer_aerospace_aerospace_engineer', 'warrant_officer', 'Aerospace', 'Aerospace Engineer', 'Technical expert and Aerospace Engineer with 12+ years of specialized experience in aerospace operations and mission support. Unique combination of deep technical proficiency and leadership capability developed through warrant officer service. Proven ability to bridge the gap between technical execution and strategic objectives in Aerospace environments.', NULL) ON CONFLICT DO NOTHING;
INSERT INTO dict_professional_summaries (template_name, rank_tier, target_industry, target_role, template_text, example_output) VALUES ('warrant_officer_aerospace_mission_planner', 'warrant_officer', 'Aerospace', 'Mission Planner', 'Subject matter expert in aerospace operations and mission support with 12+ years of progressive technical leadership. As a warrant officer, developed unparalleled depth in mission planning, flight operations, and systems engineering. Skilled in technical mentoring, process optimization, and translating complex requirements into actionable solutions for Aerospace organizations.', NULL) ON CONFLICT DO NOTHING;
