INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('technology_technical_project_manager', 'Technology', 'Technical Project Manager', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'During my military service, I managed complex IT infrastructure supporting {user_count}+ users across multiple locations. I led teams of {team_size} technicians in maintaining {uptime}% system availability while implementing security protocols that protected classified networks. My experience with {tech_stack} and enterprise systems administration translates directly to your technology environment.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'I am enthusiastic about the opportunity to bring my military-honed skills to {company_name} and am confident I can make an immediate impact. I would appreciate the chance to discuss my qualifications in more detail. Please feel free to contact me at {phone} or {email} to schedule a conversation.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Technology Technical Project Manager roles') ON CONFLICT DO NOTHING;
