INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('consulting_strategy_analyst', 'Consulting', 'Strategy Analyst', 'With {years} years of proven leadership and operational excellence in the {branch}, I am excited to apply for the {role_type} role at {company_name}. My military career has equipped me with the skills, resilience, and results-driven mindset that {company_name} values.', 'Throughout my service, I served in advisory roles requiring rapid assessment of organizational challenges and development of actionable recommendations. I have experience in process improvement, change management, and stakeholder engagement — core consulting competencies that I am eager to apply at {company_name}.', 'What sets me apart is not just my technical background but the leadership philosophy I developed through military service. I believe in servant leadership, accountability, and empowering team members to achieve their full potential. I have consistently built teams that exceed expectations, and I am eager to bring this approach to {company_name}.', 'Thank you for considering my application for the {role_type} position. I am confident that my {years} years of military leadership and operational experience make me a strong candidate. I welcome the opportunity to discuss how I can contribute to {company_name}''s mission and would be happy to provide additional references or information upon request.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Consulting Strategy Analyst roles') ON CONFLICT DO NOTHING;
INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('consulting_operations_consultant', 'Consulting', 'Operations Consultant', 'I am eager to bring my {years} years of military experience to the {role_type} position at {company_name}. My background in {domain} has prepared me to deliver immediate value in a fast-paced civilian environment.', 'My military background has honed my ability to analyze complex problems, develop strategic solutions, and drive organizational change. I have led cross-functional teams of {team_size}+ in high-pressure environments, managed projects valued at ${value}+, and consistently delivered results that exceeded expectations. These skills are the foundation of effective consulting.', 'My military training has instilled in me a deep appreciation for teamwork, planning, and execution. I am accustomed to working in environments where precision matters, deadlines are non-negotiable, and adaptability is essential. These qualities, combined with my commitment to professional development and continuous learning, make me a strong addition to your team.', 'I am enthusiastic about the opportunity to bring my military-honed skills to {company_name} and am confident I can make an immediate impact. I would appreciate the chance to discuss my qualifications in more detail. Please feel free to contact me at {phone} or {email} to schedule a conversation.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle