INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('consulting_change_management_lead', 'Consulting', 'Change Management Lead', 'As a transitioning military professional with {years}+ years of service, I am confident that my expertise in {domain} makes me an excellent candidate for the {role_type} position at {company_name}. I have consistently delivered results in high-stakes environments and am ready to bring that same commitment to your organization.', 'Throughout my service, I served in advisory roles requiring rapid assessment of organizational challenges and development of actionable recommendations. I have experience in process improvement, change management, and stakeholder engagement — core consulting competencies that I am eager to apply at {company_name}.', 'I am particularly drawn to {company_name} because of your commitment to {company_value}. My military background has given me firsthand experience with the importance of {related_value}, and I am excited to contribute to an organization that shares these principles. I am confident that my leadership experience and technical skills will help drive your team''s success.', 'I look forward to the opportunity to discuss how my background in {domain} aligns with {company_name}''s goals. My military service has prepared me to excel in demanding environments, and I am eager to demonstrate my value to your organization. Thank you for your time and consideration.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element"