INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('defense_acquisition_specialist', 'Defense', 'Acquisition Specialist', 'The {role_type} opportunity at {company_name} immediately caught my attention because of its alignment with my {years}-year military career in {domain}. I have spent my career building teams, solving complex problems, and driving operational improvements — skills that translate directly to this role.', 'With {years} years in the {branch}, I bring deep expertise in defense operations, program management, and systems acquisition. I have managed programs valued at ${value}+, held {clearance_level} clearances, and worked directly with defense contractors on complex technical programs. My understanding of the defense ecosystem makes me an ideal fit for this role.', 'Throughout my career, I have consistently demonstrated the ability to learn quickly, adapt to new environments, and deliver results. Transitioning from military to civilian service is a challenge I embrace with the same determination that defined my military career. I am committed to bringing value from day one and growing with {company_name} over the long term.', 'I would welcome the opportunity to discuss how my military experience and skills can contribute to {company_name}''s success. I am available for an interview at your convenience and can be reached at {phone} or {email}. Thank you for considering my application, and I look forward to the possibility of joining your team.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","clearance_level":"Security clearance level","company_value":"Company value or mission element","related_value":"Related military value or principle"}'::jsonb, 'Military-to-civilian cover letter template for Defense Acquisition Specialist roles') ON CONFLICT DO NOTHING;
