INSERT INTO dict_cover_letter_templates (template_name, industry, role_type, opening_paragraph, body_paragraph_1, body_paragraph_2, closing_paragraph, placeholders, notes) VALUES ('aerospace_aerospace_engineer', 'Aerospace', 'Aerospace Engineer', 'I am writing to express my strong interest in the {role_type} position at {company_name}. As a {years}-year military veteran with extensive experience in {domain}, I bring a unique combination of leadership, discipline, and technical expertise that directly aligns with your team''s needs.', 'With {years} years in military aviation/space operations, I bring deep expertise in mission planning, flight operations, and aerospace systems management. I have managed assets valued at ${value}+, maintained {safety_record} safety records, and led teams of {team_size} in executing complex operations. My experience directly supports {company_name}''s aerospace mission.', 'Beyond technical qualifications, my military experience has developed exceptional soft skills that are critical in any organization. I am adept at building high-performing teams, communicating complex information to diverse audiences, and maintaining composure under pressure. I bring a strong work ethic, unwavering integrity, and a commitment to continuous improvement that will add immediate value to your organization.', 'I would welcome the opportunity to discuss how my military experience and skills can contribute to {company_name}''s success. I am available for an interview at your convenience and can be reached at {phone} or {email}. Thank you for considering my application, and I look forward to the possibility of joining your team.', '{"company_name":"Target company name","role_type":"Target job title","years":"Years of military service","branch":"Military branch of service","domain":"Primary area of expertise","phone":"Contact phone number","email":"Contact email address","military_title":"Most recent military title/rank","team_size":"Number of personnel led","